    48→	var nextCursor *string
    49→	if len(rawCourses) > pageSize {
    50→		s := rawCourses[pageSize-1].CourseID.String()
    51→		nextCursor = &s
    52→	}
    53→
    54→	return GetCoursesResult{Courses: coursesItems, Cursor: nextCursor}, nil
    55→}
