			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if len(body.Courses) != 1 {
			t.Fatalf("コースが1件返ること: got %d", len(body.Courses))
		}
		if body.Courses[0].Title != "タイトル一致テスト専用コース" {
			t.Errorf("タイトルが一致すること: got %s", body.Courses[0].Title)
		}
	})

	t.Run("キーワードで説明を検索できる", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "説明文一致テスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		handlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("ステータスコードが200であること: got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if len(body.Courses) != 1 {
			t.Fatalf("コースが1件返ること: got %d", len(body.Courses))
		}
		if body.Courses[0].Title != "通常コースB" {
			t.Errorf("タイトルが一致すること: got %s", body.Courses[0].Title)
		}
	})

	t.Run("次のページがある場合200件とカーソルが返る", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "ページネーションテスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		handlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("ステータスコードが200であること: got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body.Cursor == nil {
			t.Error("カーソルが返ること")
		}
		if len(body.Courses) != 200 {
			t.Errorf("コースが200件返ること: got %d", len(body.Courses))
		}
	})

	t.Run("カーソルを使って2ページ目が取得できる", func(t *testing.T) {
		// 1ページ目を取得
		params := url.Values{}
		params.Set("keyword", "ページネーションテスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()
		handlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("1ページ目のステータスコードが200であること: got %d", res.StatusCode)
		}
		var firstPage GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&firstPage); err != nil {
			t.Fatalf("1ページ目のレスポンスボディのデコードに失敗しました: %v", err)
		}
		if firstPage.Cursor == nil {
			t.Fatal("1ページ目のカーソルが返ること")
		}

		// 2ページ目を取得
		params2 := url.Values{}
		params2.Set("keyword", "ページネーションテスト")
		params2.Set("cursor", *firstPage.Cursor)
		req2 := httptest.NewRequest("GET", "/v1/courses?"+params2.Encode(), nil)
		w2 := httptest.NewRecorder()
		handlers.GetCoursesHandler(w2, req2)

		res2 := w2.Result()
		if res2.StatusCode != http.StatusOK {
			t.Fatalf("2ページ目のステータスコードが200であること: got %d", res2.StatusCode)
		}
		var secondPage GetCoursesResult
		if err := json.NewDecoder(res2.Body).Decode(&secondPage); err != nil {
			t.Fatalf("2ページ目のレスポンスボディのデコードに失敗しました: %v", err)
		}
		if len(secondPage.Courses) != 1 {
			t.Fatalf("2ページ目のコースが1件返ること: got %d", len(secondPage.Courses))
		}

		// 1ページ目と重複しないことを確認
		firstPageIDs := make(map[string]bool)
		for _, course := range firstPage.Courses {
			firstPageIDs[course.CourseId] = true
		}
		for _, course := range secondPage.Courses {
			if firstPageIDs[course.CourseId] {
				t.Errorf("2ページ目のコースが1ページ目と重複している: %s", course.CourseId)
			}
		}
	})

	t.Run("次のページがない場合カーソルが null", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "タイトル一致テスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		handlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("ステータスコードが200であること: got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body.Cursor != nil {
			t.Errorf("カーソルが null であること: got %s", *body.Cursor)
		}
		if len(body.Courses) >= 200 {
			t.Errorf("コースが200件未満であること: got %d", len(body.Courses))
		}
	})
}

package queries

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/validation"
	"github.com/jackc/pgx/v5/pgtype"
)

const pageSize = 200

type GetCoursesQuery interface {
	GetCourses(ctx context.Context, arg db.GetCoursesParams) ([]db.GetCoursesRow, error)
}

type Handlers struct {
	query GetCoursesQuery
}

type GetCoursesResult struct {
	Courses []db.GetCoursesRow `json:"courses"`
	Cursor  *string            `json:"cursor"`
}

func NewCoursesHandlers(qs GetCoursesQuery) *Handlers {
	return &Handlers{query: qs}
}

func parseGetCoursesQuery(r *http.Request) (keyword, cursor string, err error) {
	keyword = r.URL.Query().Get("keyword")
	cursor = r.URL.Query().Get("cursor")

	if len([]rune(keyword)) > 40 {
		return "", "", fmt.Errorf("keyword must be 40 characters or less")
	}
	if cursor != "" && !uuid.IsValidUuid(cursor) {
		return "", "", fmt.Errorf("invalid cursor")
	}

	return keyword, cursor, nil
}

func (handler *Handlers) GetCoursesHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	keyword, cursor, err := parseGetCoursesQuery(r)
	if err != nil {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": err.Error()})
		return
	}

	var cursorUuid pgtype.UUID
	if cursor != "" {
		if err := cursorUuid.Scan(cursor); err != nil {
			log.Printf("cursor scan error: %v", err)
			w.WriteHeader(http.StatusBadRequest)
			_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "invalid cursor"})
			return
		}
	}

	rawCourses, err := handler.query.GetCourses(r.Context(), db.GetCoursesParams{Cursor: cursorUuid, Keyword: keyword, Size: pageSize + 1})
	if err != nil {
		log.Printf("GetCourses error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "INTERNAL_SERVER_ERROR", "message": "internal server error"})
		return
	}

	courses := rawCourses[0:min(len(rawCourses), pageSize)]

	var nextCursor *string
	if len(rawCourses) > pageSize {
		s := rawCourses[pageSize-1].CourseId.String()
		nextCursor = &s
	}

	_ = json.NewEncoder(w).Encode(GetCoursesResult{Courses: courses, Cursor: nextCursor})
}

