		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body.Cursor != nil {
			t.Errorf("カーソルが null であること: got %s", *body.Cursor)
		}
		if len(body.Courses) >= 200 {
			t.Errorf("コースが200件未満であること: got %d", len(body.Courses))
		}
	})
}

